import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { Trophy, Users, MapPin, Calendar } from 'lucide-react';

export default function Home() {
  return (
    <div style={{ flex: 1 }}>
      {/* Hero Section */}
